#include "qp/replay/replay_engine.hpp"
namespace qp::replay { ReplayEngine::ReplayEngine(ReplayConfig config): config_(config) {} void ReplayEngine::add_sink(ReplaySink& sink){ sinks_.push_back(&sink); } Result<ReplayStats> ReplayEngine::run(EventSource& source){ stats_={}; clock_=ReplayClock{}; while(true){ auto nxt=source.next(); if(!nxt) return Err<ReplayStats>(nxt.error()); auto opt=std::move(nxt).value(); if(!opt) break; auto ev=*opt; ++stats_.events_seen; auto ts=event_time(ev); if(config_.time_range && !config_.time_range->contains(ts)){ ++stats_.events_filtered; continue; } if(config_.max_events && stats_.events_dispatched>=config_.max_events) break; if(config_.require_monotonic_time){ auto clk=clock_.advance_to(ts); if(!clk) return Err<ReplayStats>(clk.error()); } if(config_.validate_market_data && std::holds_alternative<MarketDataEvent>(ev)){ auto ok=data::validate(std::get<MarketDataEvent>(ev).data); if(!ok){ ++stats_.validation_errors; return Err<ReplayStats>(ok.error()); } } for(auto* sink:sinks_){ auto ok=sink->on_event(ev); if(!ok) return Err<ReplayStats>(ok.error()); } ++stats_.events_dispatched; } for(auto* sink:sinks_){ auto ok=sink->on_end(); if(!ok) return Err<ReplayStats>(ok.error()); } return Ok(stats_); } }
